import java.lang.annotation.*;
import java.lang.reflect.*;

// 1. Define the Custom Annotation
@Retention(RetentionPolicy.RUNTIME)
@Target(ElementType.METHOD)
@interface RunMe {
    int times() default 1;
}

// 2. Use the Annotation
class MyTests {
    @RunMe(times = 3)
    public void testA() {
        System.out.println("Running test A");
    }

    public void testB() {
        System.out.println("Running test B (No Annotation)");
    }
}

// 3. Process the Annotation via Reflection
public class AnnotationProcessor {
    public static void main(String[] args) throws Exception {
        MyTests obj = new MyTests();
        Class<?> clazz = obj.getClass();

        for (Method method : clazz.getDeclaredMethods()) {
            if (method.isAnnotationPresent(RunMe.class)) {
                RunMe annotation = method.getAnnotation(RunMe.class);
                for (int i = 0; i < annotation.times(); i++) {
                    method.invoke(obj); // Dynamically invoke the method
                }
            }
        }
    }
}

